import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';

// 保持原有的lessonData数据不变...

export default function VideoPage() {
  const { id } = useParams();
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [id]);
  
  const navigate = useNavigate();
  const currentId = parseInt(id || "1");
  const maxLessonId = Object.keys(lessonData).length;
  const nextId = currentId + 1 > maxLessonId ? 1 : currentId + 1;

  const { videoUrl, quiz } = lessonData[currentId] || lessonData[1];

  const [answers, setAnswers] = useState(Array(quiz.length).fill(null));
  const [submitted, setSubmitted] = useState(false);
  const [aiHelpIndex, setAiHelpIndex] = useState(null);

  const handleOptionChange = (index, option) => {
    const newAnswers = [...answers];
    newAnswers[index] = option;
    setAnswers(newAnswers);
  };

  const handleSubmit = () => {
    setSubmitted(true);
    setAiHelpIndex(null);
  };

  const score = answers.reduce((acc, cur, idx) => {
    return cur === quiz[idx].answer ? acc + 2 : acc;
  }, 0);

  return (
    <div className="content-card"> {/* 使用全局样式类 */}
      <div style={styles.container}>
        <h2 style={styles.title}>📹 Lesson {currentId} - Watch & Quiz</h2>

        {/* 视频区域 */}
        <div style={styles.videoWrapper}>
          <iframe
            width="100%"
            height="400" 
            src={videoUrl}
            title={`Lesson ${currentId}`}
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          ></iframe>
        </div>

        {/* 问题区 */}
        <div style={styles.quizSection}>
          {quiz.map((q, index) => (
            <div key={index} style={styles.questionBlock}>
              <p style={styles.questionText}><strong>{q.question}</strong></p>
              <div style={styles.optionsContainer}>
                {q.options.map((opt, optIdx) => (
                  <label key={optIdx} style={styles.option}>
                    <input
                      type="radio"
                      name={`question-${index}`}
                      value={optIdx}
                      disabled={submitted}
                      checked={answers[index] === optIdx}
                      onChange={() => handleOptionChange(index, optIdx)}
                      style={styles.radioInput}
                    />
                    <span style={styles.optionText}>{opt}</span>
                  </label>
                ))}
              </div>
              
              {submitted && answers[index] !== q.answer && (
                <p style={styles.wrongAnswer}>❌ {q.help}</p>
              )}
              
              {!submitted && (
                <button
                  style={styles.helpBtn}
                  onClick={() => setAiHelpIndex(aiHelpIndex === index ? null : index)}
                >
                  {aiHelpIndex === index ? '🤖 Hide Hint' : '🤖 Get Hint'}
                </button>
              )}
              
              {aiHelpIndex === index && (
                <div style={styles.aiResponse}>
                  <p style={styles.aiText}>{q.help}</p>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* 提交与导航 */}
        <div style={styles.actionBar}>
          {!submitted ? (
            <button 
              onClick={handleSubmit} 
              style={styles.submitBtn}
              disabled={answers.some(a => a === null)}
            >
              Submit Answers
            </button>
          ) : (
            <div style={styles.resultContainer}>
              <p style={styles.score}>Your score: <strong>{score}/{quiz.length * 2}</strong></p>
              <div style={styles.navigation}>
                <button
                  onClick={() => navigate(`/video/${currentId > 1 ? currentId - 1 : maxLessonId}`)}
                  style={styles.navButton}
                >
                  ◀️ Previous
                </button>
                <button
                  onClick={() => navigate(`/video/${nextId}`)}
                  style={styles.navButton}
                >
                  Next ▶️
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  container: {
    padding: '1.5em',
    fontFamily: 'Arial, sans-serif',
    maxWidth: '800px',
    margin: '0 auto',
  },
  title: {
    textAlign: 'center',
    marginBottom: '1em',
    color: '#00796b',
    fontSize: '1.5em'
  },
  videoWrapper: {
    marginBottom: '2em',
    borderRadius: '12px',
    overflow: 'hidden',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    backgroundColor: '#000' // 视频加载前的背景色
  },
  quizSection: {
    marginBottom: '1.5em'
  },
  questionBlock: {
    marginBottom: '1.5em',
    backgroundColor: '#fff',
    padding: '1.2em',
    borderRadius: '10px',
    boxShadow: '0 2px 8px rgba(0,0,0,0.05)'
  },
  questionText: {
    fontSize: '1.1em',
    marginBottom: '0.8em',
    color: '#333'
  },
  optionsContainer: {
    marginLeft: '0.5em'
  },
  option: {
    display: 'flex',
    alignItems: 'center',
    margin: '0.5em 0',
    cursor: 'pointer'
  },
  radioInput: {
    marginRight: '0.8em',
    cursor: 'pointer'
  },
  optionText: {
    fontSize: '1em'
  },
  wrongAnswer: {
    color: '#d32f2f',
    backgroundColor: '#ffebee',
    padding: '0.8em',
    borderRadius: '6px',
    marginTop: '0.8em'
  },
  helpBtn: {
    marginTop: '0.8em',
    padding: '0.4em 1em',
    backgroundColor: '#e3f2fd',
    color: '#1565c0',
    border: 'none',
    borderRadius: '20px',
    cursor: 'pointer',
    fontSize: '0.9em',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#bbdefb'
    }
  },
  aiResponse: {
    marginTop: '0.8em',
    backgroundColor: '#e8f5e9',
    padding: '0.8em',
    borderRadius: '6px',
    borderLeft: '4px solid #4caf50'
  },
  aiText: {
    margin: 0,
    color: '#2e7d32'
  },
  actionBar: {
    marginTop: '1.5em'
  },
  submitBtn: {
    width: '100%',
    padding: '0.8em',
    backgroundColor: '#4fb3bf',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    fontSize: '1em',
    cursor: 'pointer',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#00838f'
    },
    ':disabled': {
      backgroundColor: '#bdbdbd',
      cursor: 'not-allowed'
    }
  },
  resultContainer: {
    textAlign: 'center'
  },
  score: {
    fontSize: '1.2em',
    marginBottom: '1em',
    color: '#00796b'
  },
  navigation: {
    display: 'flex',
    justifyContent: 'center',
    gap: '1em'
  },
  navButton: {
    padding: '0.6em 1.2em',
    backgroundColor: '#4fb3bf',
    color: 'white',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '1em',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#00838f'
    }
  }
};
